import { ChangeDetectionStrategy, Component } from '@angular/core';

type Role = 'Admin' | 'Editor' | 'Viewer';
type SortKey = 'id' | 'name' | 'role';
type SortDirection = 'asc' | 'desc';
type AriaSortDirection = 'ascending' | 'descending';

interface User {
  id: number;
  name: string;
  email: string;
  role: Role;
}

const USERS: readonly User[] = [
  { id: 1, name: 'Alice Johnson', email: 'alice@example.com', role: 'Admin' },
  { id: 2, name: 'Bob Smith', email: 'bob@example.com', role: 'Editor' },
  { id: 3, name: 'Carla Perez', email: 'carla@example.com', role: 'Viewer' },
  { id: 4, name: 'David Kim', email: 'david@example.com', role: 'Editor' },
  { id: 5, name: 'Emma Brown', email: 'emma@example.com', role: 'Viewer' },
  { id: 6, name: 'Frank Wu', email: 'frank@example.com', role: 'Admin' },
  { id: 7, name: 'Grace Lee', email: 'grace@example.com', role: 'Viewer' },
  { id: 8, name: 'Henry Ford', email: 'henry@example.com', role: 'Editor' },
  { id: 9, name: 'Ivy Stone', email: 'ivy@example.com', role: 'Viewer' },
  { id: 10, name: 'Jack Ryan', email: 'jack@example.com', role: 'Viewer' },
  { id: 11, name: 'Karen Diaz', email: 'karen@example.com', role: 'Editor' },
  { id: 12, name: 'Leo Walker', email: 'leo@example.com', role: 'Viewer' },
  { id: 13, name: 'Mia Clark', email: 'mia@example.com', role: 'Admin' }
];

@Component({
  selector: 'app-root',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  readonly users = USERS;

  query = '';
  pageSize = 5;
  currentPage = 0;
  sortKey: SortKey = 'id';
  sortDirection: SortDirection = 'asc';
  selectedIds = new Set<number>();
  tableStatus = 'Page 1 of 3. Showing 5 of 13 users.';

  private filteredCache: User[] = [...USERS];
  private sortedCache: User[] = [...USERS];
  pageUsers: User[] = USERS.slice(0, 5);
  totalPages = 3;

  get filteredUsers(): User[] {
    return this.filteredCache;
  }

  get sortedUsers(): User[] {
    return this.sortedCache;
  }

  get isFirstPage(): boolean {
    return this.currentPage === 0;
  }

  get isLastPage(): boolean {
    return this.currentPage >= this.totalPages - 1;
  }

  get resultSummary(): string {
    return this.userCount(this.filteredCache.length) + ' found.';
  }

  get selectionSummary(): string {
    return this.userCount(this.selectedIds.size) + ' selected.';
  }

  get allPageSelected(): boolean {
    return this.pageUsers.length > 0 &&
      this.pageUsers.every((user) => this.selectedIds.has(user.id));
  }

  get somePageSelected(): boolean {
    return !this.allPageSelected &&
      this.pageUsers.some((user) => this.selectedIds.has(user.id));
  }

  get pageSelectionState(): 'true' | 'mixed' | 'false' {
    if (this.allPageSelected) return 'true';
    if (this.somePageSelected) return 'mixed';
    return 'false';
  }

  onSearchInput(event: Event): void {
    this.query = (event.target as HTMLInputElement).value;
    this.currentPage = 0;
    this.refreshView();
    this.announcePage();
  }

  onSearchKeyDown(event: KeyboardEvent): void {
    if (event.key !== 'Escape') return;
    event.preventDefault();
    this.query = '';
    this.currentPage = 0;
    (event.target as HTMLInputElement).value = '';
    this.refreshView();
    this.tableStatus = 'Search cleared. 13 users found.';
  }

  onPageSizeChange(event: Event): void {
    this.pageSize = Number((event.target as HTMLSelectElement).value) === 10 ? 10 : 5;
    this.currentPage = 0;
    this.refreshView();
    this.announcePage();
  }

  sortBy(key: SortKey): void {
    if (this.sortKey === key) {
      this.sortDirection = this.sortDirection === 'asc' ? 'desc' : 'asc';
    } else {
      this.sortKey = key;
      this.sortDirection = 'asc';
    }
    this.currentPage = 0;
    this.refreshView();
    this.announcePage();
  }

  sortAriaValue(key: SortKey): AriaSortDirection | null {
    if (this.sortKey !== key) return null;
    return this.sortDirection === 'asc' ? 'ascending' : 'descending';
  }

  sortIndicator(key: SortKey): string {
    if (this.sortKey !== key) return '↕';
    return this.sortDirection === 'asc' ? '↑' : '↓';
  }

  goPrevious(): void {
    if (this.isFirstPage) return;
    this.currentPage -= 1;
    this.refreshPage();
    this.announcePage();
  }

  goNext(): void {
    if (this.isLastPage) return;
    this.currentPage += 1;
    this.refreshPage();
    this.announcePage();
  }

  isSelected(userId: number): boolean {
    return this.selectedIds.has(userId);
  }

  toggleRow(userId: number, checked: boolean): void {
    const next = new Set(this.selectedIds);
    if (checked) next.add(userId);
    else next.delete(userId);
    this.selectedIds = next;
    this.tableStatus = this.selectionSummary;
  }

  togglePage(checked: boolean): void {
    const next = new Set(this.selectedIds);
    for (const user of this.pageUsers) {
      if (checked) next.add(user.id);
      else next.delete(user.id);
    }
    this.selectedIds = next;
    this.tableStatus = this.selectionSummary;
  }

  clearSelection(): void {
    if (!this.selectedIds.size) return;
    this.selectedIds = new Set<number>();
    this.tableStatus = 'Selection cleared. 0 users selected.';
  }

  private refreshView(): void {
    const needle = this.query.trim().toLowerCase();
    this.filteredCache = needle
      ? this.users.filter((user) =>
          user.name.toLowerCase().includes(needle) ||
          user.email.toLowerCase().includes(needle) ||
          user.role.toLowerCase().includes(needle)
        )
      : [...this.users];

    this.sortedCache = this.filteredCache
      .map((user, sourceIndex) => ({ user, sourceIndex }))
      .sort((left, right) => {
        const comparison = this.compareUsers(left.user, right.user);
        if (comparison === 0) return left.sourceIndex - right.sourceIndex;
        return this.sortDirection === 'asc' ? comparison : -comparison;
      })
      .map(({ user }) => user);

    this.totalPages = Math.max(1, Math.ceil(this.sortedCache.length / this.pageSize));
    this.currentPage = Math.min(this.currentPage, this.totalPages - 1);
    this.refreshPage();
  }

  private refreshPage(): void {
    const start = this.currentPage * this.pageSize;
    this.pageUsers = this.sortedCache.slice(start, start + this.pageSize);
  }

  private compareUsers(left: User, right: User): number {
    if (this.sortKey === 'id') return left.id - right.id;
    const leftValue = (this.sortKey === 'name' ? left.name : left.role).toLowerCase();
    const rightValue = (this.sortKey === 'name' ? right.name : right.role).toLowerCase();
    return leftValue < rightValue ? -1 : leftValue > rightValue ? 1 : 0;
  }

  private userCount(count: number): string {
    return count + (count === 1 ? ' user' : ' users');
  }

  private announcePage(): void {
    this.tableStatus =
      'Page ' + (this.currentPage + 1) + ' of ' + this.totalPages +
      '. Showing ' + this.pageUsers.length + ' of ' +
      this.userCount(this.filteredCache.length) + '.';
  }
}
